-- Realtime: every 5 min (data_type=1)
-- Minute:   every 10 min (data_type=2)01kt83p6sbzt1b8m5fbq9gzqkw
-- Hour:     every 1 hour (data_type=3)01KT83P6SBZT1B8M5FBQ9GZQKW
-- ========================================
CREATE TABLE `t_data_out_2025_01kt83p6sbzt1b8m5fbq9gzqkw` (
  `out_id` varchar(20) NOT NULL COMMENT '主键id',
  `data_type` tinyint DEFAULT NULL COMMENT '数据类型：1实时数据，2分钟数据，3小时数据；4日数据',
  `data_alarm` tinyint DEFAULT '0' COMMENT '该时刻是否有报警：0：正常；1：发生报警',
  `monitor_time` datetime DEFAULT NULL COMMENT '污染物监测时间',
  `data_info` json DEFAULT NULL COMMENT '污染信息',
  `create_time` datetime DEFAULT NULL COMMENT '数据创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '数据更新时间',
  PRIMARY KEY (`out_id`),
  KEY `idx_data_type` (`data_type`,`monitor_time`),
  KEY `idx_data_alarm` (`data_alarm`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='排口监测数据';
